<template><div class="panel"><div class="section-head"><div><h2>岗位管理</h2><p>维护用户岗位信息。</p></div><el-button v-if="auth.hasPermission('system:position:create')" type="primary" @click="open()">新增岗位</el-button></div><el-table :data="rows"><el-table-column prop="code" label="编码"/><el-table-column prop="name" label="名称"/><el-table-column prop="sortOrder" label="排序"/><el-table-column label="操作"><template #default="s"><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="query.page" :page-size="query.size" :total="total" layout="total, prev, pager, next"/><el-dialog v-model="visible" :title="form.id?'编辑岗位':'新增岗位'"><el-form label-width="90px"><el-form-item label="编码"><el-input v-model="form.code"/></el-form-item><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="排序"><el-input-number v-model="form.sortOrder"/></el-form-item><el-form-item label="启用"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import {computed,onMounted,reactive,ref} from 'vue';import {ElMessage,ElMessageBox} from 'element-plus';import http from '../api/http';import {useAuthStore} from '../stores/auth';const auth=useAuthStore(),allRows=ref([]),visible=ref(false),form=reactive({id:null,code:'',name:'',sortOrder:0,enabled:true});const query=reactive({page:1,size:10});const total=computed(()=>allRows.value.length);const rows=computed(()=>allRows.value.slice((query.page-1)*query.size,query.page*query.size));async function load(){allRows.value=(await http.get('/system/positions')).data}/** 打开岗位窗口。 */function open(row){Object.assign(form,row?{...row}:{id:null,code:'',name:'',sortOrder:0,enabled:true});visible.value=true}/** 保存岗位。 */async function save(){form.id?await http.put(`/system/positions/${form.id}`,form):await http.post('/system/positions',form);visible.value=false;await load();ElMessage.success('保存成功')}/** 删除岗位。 */async function remove(row){await ElMessageBox.confirm(`确认删除岗位「${row.name}」？`,'删除确认',{type:'warning'});await http.delete(`/system/positions/${row.id}`);await load()}onMounted(load)</script>
